import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const DEMO = {
  admin: { email: 'admin@college.edu', password: 'Admin@123', label: 'Administrator' },
  student: { email: 'student@college.edu', password: 'Student@123', label: 'Student' },
};

const ADMIN_FEATURES = [
  { icon: '📊', title: 'Analytics Dashboard', desc: 'Real-time collection stats & charts' },
  { icon: '👨‍🎓', title: 'Student Management', desc: 'Add, edit & track all students' },
  { icon: '💰', title: 'Fee Collection', desc: 'Bulk generate & collect payments' },
  { icon: '🔔', title: 'Smart Reminders', desc: 'Automated payment notifications' },
];

const STUDENT_FEATURES = [
  { icon: '💳', title: 'View My Fees', desc: 'Track all payments & dues' },
  { icon: '🧾', title: 'Digital Receipts', desc: 'Download & print receipts' },
  { icon: '📅', title: 'Payment Schedule', desc: 'Know when fees are due' },
  { icon: '🚌', title: 'Route Info', desc: 'Your bus route & boarding point' },
];

export default function Login() {
  const [role, setRole] = useState('student');
  const [email, setEmail] = useState(DEMO.student.email);
  const [password, setPassword] = useState(DEMO.student.password);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login, logout } = useAuth();
  const navigate = useNavigate();

  const switchRole = (r) => {
    setRole(r);
    setEmail(DEMO[r].email);
    setPassword(DEMO[r].password);
    setError('');
  };

  const fillDemo = () => {
    setEmail(DEMO[role].email);
    setPassword(DEMO[role].password);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const data = await login(email, password);
      if (role === 'admin' && data.user.role !== 'admin') {
        logout();
        setError('This account is not an administrator. Switch to Student login.');
        return;
      }
      if (role === 'student' && data.user.role !== 'student') {
        logout();
        setError('This account is not a student. Switch to Admin login.');
        return;
      }
      navigate(data.user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password');
    } finally {
      setLoading(false);
    }
  };

  const features = role === 'admin' ? ADMIN_FEATURES : STUDENT_FEATURES;

  return (
    <div className="login-page">
      <div className="login-bg-shapes">
        <div className="shape shape-1" />
        <div className="shape shape-2" />
        <div className="shape shape-3" />
      </div>

      <div className="login-container">
        <div className="login-brand">
          <div className="login-brand-inner">
            <div className="brand-badge">🚌 Campus Transport</div>
            <h1>Bus Fee Management System</h1>
            <p>Streamline college bus transportation fees — track payments, manage routes, and keep everyone informed.</p>
            <div className="login-features-grid">
              {features.map(f => (
                <div className="login-feature-card" key={f.title}>
                  <span className="feat-icon">{f.icon}</span>
                  <div>
                    <strong>{f.title}</strong>
                    <span>{f.desc}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="login-form-side">
          <div className="login-card">
            <div className="login-card-header">
              <span className="login-emoji">🚌</span>
              <h2>Welcome Back</h2>
              <p>Sign in to your {role === 'admin' ? 'admin' : 'student'} portal</p>
            </div>

            <div className="role-tabs">
              <button type="button" className={`role-tab ${role === 'student' ? 'active' : ''}`} onClick={() => switchRole('student')}>
                <span>👨‍🎓</span> Student
              </button>
              <button type="button" className={`role-tab ${role === 'admin' ? 'active' : ''}`} onClick={() => switchRole('admin')}>
                <span>👨‍💼</span> Admin
              </button>
            </div>

            {error && <div className="login-error"><span>⚠️</span> {error}</div>}

            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Email Address</label>
                <div className="input-wrap">
                  <span className="input-icon">📧</span>
                  <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="your@college.edu" required />
                </div>
              </div>
              <div className="form-group">
                <label>Password</label>
                <div className="input-wrap">
                  <span className="input-icon">🔒</span>
                  <input type={showPass ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} placeholder="Enter password" required />
                  <button type="button" className="toggle-pass" onClick={() => setShowPass(!showPass)} aria-label="Toggle password">
                    {showPass ? '🙈' : '👁️'}
                  </button>
                </div>
              </div>
              <button type="submit" className="btn btn-primary btn-lg login-submit" disabled={loading}>
                {loading ? <><span className="spinner spinner-sm" /> Signing in...</> : `Sign In as ${DEMO[role].label}`}
              </button>
            </form>

            <div className="demo-box">
              <div className="demo-box-header">
                <span>Demo Credentials</span>
                <button type="button" className="demo-fill-btn" onClick={fillDemo}>Use Demo</button>
              </div>
              <div className="demo-cred">
                <span className="demo-role-badge">{role === 'admin' ? '👨‍💼 Admin' : '👨‍🎓 Student'}</span>
                <code>{DEMO[role].email}</code>
                <code>{DEMO[role].password}</code>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
